        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new IbQuoteUpdateMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[IbQuoteUpdateMessage](sbeTemplateId=");
            builder.Append(IbQuoteUpdateMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(IbQuoteUpdateMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != IbQuoteUpdateMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(IbQuoteUpdateMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != IbQuoteUpdateMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(IbQuoteUpdateMessage.BlockLength);
            builder.Append("):");

            builder.Append("TickerId=");
            builder.Append(this.TickerId);
            builder.Append('|');
            builder.Append("BidSize=");
            builder.Append(this.BidSize);
            builder.Append('|');
            builder.Append("AskSize=");
            builder.Append(this.AskSize);
            builder.Append('|');
            builder.Append("LastSize=");
            builder.Append(this.LastSize);
            builder.Append('|');
            builder.Append("Volume=");
            builder.Append(this.Volume);
            builder.Append('|');
            builder.Append("Bid=");
            builder.Append(this.Bid);
            builder.Append('|');
            builder.Append("Ask=");
            builder.Append(this.Ask);
            builder.Append('|');
            builder.Append("Last=");
            builder.Append(this.Last);
            builder.Append('|');
            builder.Append("High=");
            builder.Append(this.High);
            builder.Append('|');
            builder.Append("Low=");
            builder.Append(this.Low);
            builder.Append('|');
            builder.Append("Open=");
            builder.Append(this.Open);
            builder.Append('|');
            builder.Append("Close=");
            builder.Append(this.Close);
            builder.Append('|');
            builder.Append("ImpliedVolatility=");
            builder.Append(this.ImpliedVolatility);
            builder.Append('|');
            builder.Append("Delta=");
            builder.Append(this.Delta);
            builder.Append('|');
            builder.Append("OptPrice=");
            builder.Append(this.OptPrice);
            builder.Append('|');
            builder.Append("PvDividend=");
            builder.Append(this.PvDividend);
            builder.Append('|');
            builder.Append("Gamma=");
            builder.Append(this.Gamma);
            builder.Append('|');
            builder.Append("Vega=");
            builder.Append(this.Vega);
            builder.Append('|');
            builder.Append("Theta=");
            builder.Append(this.Theta);
            builder.Append('|');
            builder.Append("UndPrice=");
            builder.Append(this.UndPrice);
            builder.Append('|');
            builder.Append("BidExch=");
            builder.Append('\'').Append(GetBidExch()).Append('\'');
            builder.Append('|');
            builder.Append("AskExch=");
            builder.Append('\'').Append(GetAskExch()).Append('\'');
            builder.Append('|');
            builder.Append("LastExch=");
            builder.Append('\'').Append(GetLastExch()).Append('\'');
            builder.Append('|');
            builder.Append("Symbol=");
            builder.Append('\'').Append(GetSymbol()).Append('\'');

            this.Limit = originalLimit;

